INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989427","title":"Пацаны. Том 2. За работу","author":"Дэрик Робертсон,Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002891406/140/acc8/__Patsany._Tom_2._Za_rabotu.jpg","isbn":"978-5-04-098531-9","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Супергерои в костюмах рассекают небеса. Мстители в масках крадутся в ночи. Этому миру нужен тот, кто проследит, чтобы «суперы» не отбились от рук. И такие найдутся.  Билли Бутчер, Крошка Хьюи, Молоко Матери, Француз и Самка. «Пацаны»: команда под эгидой ЦРУ. Чрезвычайно опасна. Посвятила себя борьбе с суперсилой.  За некоторыми супергероями надо приглядывать. Некоторых – контролировать. А некоторых – иногда – убирать.  И это – работа «Пацанов».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999399,"hdCover":""},{"id":"0989426","title":"Пацаны. Том 1. Самое главное","author":"Дэрик Робертсон,Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002852256/140/904e/__Patsany._Tom_1._Samoe_glavnoe.jpg","isbn":"978-5-04-097203-6","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Супергерои в костюмах рассекают небеса. Мстители в масках крадутся в ночи. Этому миру нужен тот, кто проследит, чтобы \"суперы\" не отбились от рук. И такие найдутся.  Билли Бутчер, Крошка Хьюи, Молоко Матери, Француз и Самка. \"Пацаны\": команда под эгидой ЦРУ. Чрезвычайно опасна. Посвятила себя борьбе с суперсилой. За некоторыми супергероями надо приглядывать. Некоторых - контролировать. А некоторых - иногда - убирать.  И это - работа \"Пацанов\".","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-08","rating":4,"review":"","added":9999398,"hdCover":""},{"id":"0989425","title":"Джо-Варвар","author":"Шон Гордон Мёрфи,Грант Моррисон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004046436/140/123e/__DzhoVarvar.jpg","isbn":"978-5-389-17729-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"ДЖО МЭНСОН – НЕ ГЕРОЙ. Он всего лишь тринадцатилетний мальчишка, у которого есть ручная крыса по кличке Джек, мать, выбивающаяся из последних сил, чтобы обеспечить семью, и диабет, гарантирующий ему инсулиновую кому, если вовремя не принять меры. А еще блокнот с рисунками, комната с кучей игрушек и дом, полный воспоминаний. Он обычный подросток. Но этим вечером все изменится. Джо окажется в невероятном мире, полном опасностей, – мире, удивительно знакомом, и в то же время ни на что не похожем. В этом загадочном новом мире лестницы, коридоры и двери его большого, темного дома превращаются в окутанные туманом горы, обширные пространства и неприступные врата на пути к неизведанным землям. Игрушки и ручная крыса тоже преображаются. А сам Джо становится долгожданным героем, спасителем Королевства, единственным, кто способен одолеть Короля Смерть и вернуть Свет. Джо понятия не имеет, реален ли его путь по землям Королевства или это галлюцинации, вызванные гипогликемическим шоком. Единственное, в чем он уверен – миссия должна быть выполнена, иначе первое приключение Джо-Варвара станет последним.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4.5,"review":"","added":9999397,"hdCover":""},{"id":"0989424","title":"Заражение (сборник)","author":"Том Тейлор,Стефано Гаудиано,Тревор Хершин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004575048/140/940d/__Zarazhenie_sbornik.jpg","isbn":"978-5-389-18130-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"КОНЕЦ СВЕТА УЖЕ НАСТУПИЛ! Шестьсот миллионов человек. Таково количество жертв обрушившегося на Землю биотехногенного вируса. Шестьсот миллионов зараженных. Шестьсот миллионов человек превратились в одержимых, обезумевших убийц, уничтожающих все живое на своем пути.  И это только начало.  Города. Государства. Подводные царства и райские острова. Один за другим они гибнут под натиском полчищ ходячих мертвецов. Супермен, Бэтмен, Чудо-Женщина и другие члены Лиги Справедливости встают на защиту Земли от полного уничтожения…  Но долго ли они продержатся?  Никогда прежде они не сталкивались со столь масштабной угрозой. Никакая из тех опасностей, с которыми им приходилось иметь дело, не идет в сравнение с этой трагедией и ужасом. И когда герои и злодеи, боги и чудовища уничтожены, остается лишь один вопрос:  Что станет с Величайшими Героями Мира, если сам мир погибнет?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999396,"hdCover":""},{"id":"0989423","title":"Каратель. Омнибус: Чёрное и белое. Пересекая границу. Последние дни","author":"Moritat,Эдмондсон,Герадс,Ното,Маурэр,Карнеро,Шуновер,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002907042/140/78c0/__Karatel._Omnibus_Chjornoe_i_beloe._Peresekaya_granitsu._Poslednie_dni.jpg","isbn":"978-5-04-098563-0","publisher":"Fanzon","pubDate":"2019","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"Годами Фрэнк Касл борется с преступностью в Нью-Йорке. Когда неизвестное химическое вещество уничтожает город в Мексике, он направляется к побережью океана. Химический след ведёт его в Лос-Анджелес, где Фрэнк бросает вызов банде «Дос Солес». Но у банды есть новое удивительно сильное оружие.  В городе хаос. Сгорит ли он дотла или Фрэнк примет бой?  Вырвется ли герой из плена южноамериканского наркоторговца?  А если победит ЦИИ и «Дос Солес», выскользнет ли из затягивающейся удавки «Ревущей команды»?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999395,"hdCover":""},{"id":"0989422","title":"Современный Человек-Паук. Том 8. Хобгоблин","author":"Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003615874/140/27ea/Brajan_Majkl_Bendis__Sovremennyj_ChelovekPauk._Tom_8._Hobgoblin.jpg","isbn":"","publisher":"Зодиак","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Встречайте ужасающий дебют Современного Хобгоблина. Гарри Озборн возвращается в Мидтаунскую среднюю школу, скрывая мрачный секрет, который повлияет на жизни его близких – особенно лучшего друга Питера Паркера. Но как ко всему этому причастен отец Гарри – Норман Озборн, он же Зелёный Гоблин? Затем начинается гангстерская война, нацеленная покончить со всеми бандитскими разборками, ведь Кингпин ушёл в тень, освободив место, которое стремится занять несокрушимый Кувалда! Чтобы раз и навсегда вывести этих криминальных титанов из игры, нужна команда могучих воинов, включая Железного Кулака и Лунного Рыцаря! Паучок думал, что у него раньше были проблемы, но теперь он, как никогда прежде, хочет объявить: «Питера Паркера больше нет!»","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4.5,"review":"","added":9999394,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989421","title":"Современный Человек-Паук. Том 7. Карнаж","author":"Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003251211/140/70cc/Brajan_Majkl_Bendis__Sovremennyj_ChelovekPauk._Tom_7._Karnazh.jpg","isbn":"","publisher":"Зодиак","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Хотя юный Питер Паркер уже не раз проявил себя, может ли он надеяться одолеть безжалостную машину для убийств, именуемую Карнажем? Затем странное происшествие объединяет Человека-Паука и Росомаху в самую причудливую команду в супергеройской истории! Пока они вдвоём ищут ответ на эту тайну, их жизни буквально рушатся. Что за странный феномен вынудил героев, у которых и так забот по горло, работать вместе? Плюс: Джонни Шторм осознаёт, что, несмотря на только обретённые славу и способности, у него до сих пор нет аттестата об окончании средней школы. Так куда же направится юный Человек-Факел? Именно в ту школу в Куинсе, где уже учится Питер Паркер.  Пристёгивайте ремни, ведь приключения Современного Человека-Паука продолжаются! Включает «Современный Человек-Паук» #60-71, написанные Брайаном Майклом Бендисом и проиллюстрированные Марком Багли.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999393,"hdCover":""},{"id":"0989420","title":"Подростки Мутанты Ниндзя Черепашки. Том 4. Грехи отцов","author":"Кевин Истмен,Том Валтс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002629188/140/81fc/__Podrostki_Mutanty_Nindzya_Cherepashki._Tom_4._Grehi_ottsov.jpg","isbn":"978-5-91339-547-4","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы"],"annotation":"Силы добра и зла сталкиваются вновь и вновь! Черепашки готовы к новому заданию, но что, если они так и не успеют начать новую миссию, ведь на их пути встаёт Шреддер!  Тем временем Крэнг наконец приводит свой злобный план в исполнение. Чем это грозит жителям Нью-Йорка и планеты Земля? Как далеко готовы зайти наши друзья, чтобы спасти положение?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999392,"hdCover":""},{"id":"098941f","title":"Подростки Мутанты Ниндзя Черепашки. Том 3. Тени прошлого","author":"Кевин Истмен,Кевин Истмен, Том Валтс, Дэн Данкан","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002629211/140/6949/__Podrostki_Mutanty_Nindzya_Cherepashki._Tom_3._Teni_proshlogo.jpg","isbn":"978-5-91339-546-7","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы"],"annotation":"Родное убежище черепашек разрушено до основания совместными силами Бакстера Стокмана и Старого Беса. Учитель Сплинтер похищен, братья в растерянности. Кажется, что хуже и быть не может, но тут появляется их старый враг... ШРЕДДЕР!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999391,"hdCover":""},{"id":"098941e","title":"Подростки Мутанты Ниндзя Черепашки. Том 2. Старые враги, новые враги","author":"Кевин Истмен,Кевин Истмен, Том Валтс, Дэн Данкан","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002091529/140/0c36/__Podrostki_Mutanty_Nindzya_Cherepashki._Tom_2._Starye_vragi_novye_vragi.jpg","isbn":"978-5-91339-475-0","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Черепашки узнают удивительную историю своего появления и начинают приключения как настоящая команда братьев. В это время Бакстер Стокман прибегает к новому плану по их поимке... ведь сам генерал Крэнг прибыл в Нью-Йорк и требует результатов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999390,"hdCover":""},{"id":"098941d","title":"Подростки Мутанты Ниндзя Черепашки. Том 1. Постоянство перемен","author":"Кевин Истмен,Кевин Истмен,Дэн Данкан,Том Валтс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002040565/140/74da/__Podrostki_Mutanty_Nindzya_Cherepashki._Tom_1._Postoyanstvo_peremen.jpg","isbn":"978-5-91339-401-9","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Это новый мир для Черепашек... Команда разбита, и Рафаэль вынужден скитаться по улицам Нью-Йорка в поисках еды и крыши над головой. Его братья продолжают поиски вместе с учителем Сплинтером, но единственное что они находят, — это неприятности во главе с котом-мутантом Старым Бесом и его бандой. И пока раскрывается тайна прошлого черепашьей семьи, их будущее находится под угрозой!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999389,"hdCover":""},{"id":"098941c","title":"Современный Человек-Паук. Том 6. Совершенная Шестёрка.","author":"Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002982234/140/6806/Brajan_Majkl_Bendis__Sovremennyj_ChelovekPauk._Tom_6._Sovershennaya_Shestjorka..jpg","isbn":"978-5-6041145-5-1","publisher":"Зодиак","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Старшая школа, взросление, первые свидания: в молодости нас ждет много ловушек. Соедините их с сильной личной трагедией и суперспособностями, и сможете представить мир Питера Паркера, он же Человек-Паук.  Зеленый Гоблин. Доктор Осьминог. Электор. Крэйвен-охотник. Песочный Человек. Пять самых смертоносных врагов Человека-Паука объединяются в неудержимую злую силу! Хватит ли усилий Человека-Паука и Альтимэйтс, чтобы остановить этих преступных гениев, прежде чем их власть террора распространится на весь мир? И кого они выберут шестым участником их смертельного союза? А затем вас ждёт киностудия, снимающая летний блокбастер про Человека-Паука, где современный паутиноплёт спешит высказать продюсерам своё мнение.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4.5,"review":"","added":9999388,"hdCover":""},{"id":"098941b","title":"Чумной доктор. Книга 1. Капкан","author":"Евгений Федотов,Анастасия Ким,Наталья Заидова,Наталия Воронцова,Мария Васильева,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005603940/140/bf2e/__Chumnoj_doktor._Kniga_1._Kapkan.jpg","isbn":"9785604431238","publisher":"Bubble","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Некогда Чумной Доктор был символом социальной справедливости, пока не оказался безумным убийцей в маске, остановить которого смог только бравый полицейский майор Гром. После этого Сергей Разумовский, бывший миллиардер и основатель соцсети Vmeste, скрывавшийся под маской Чумного Доктора, бесследно испарился, и уже несколько лет его официально считают погибшим… Однако, в компании лучшего друга и бывшего наёмника Олега Волкова, Разумовский тайно возвращается в родной Петербург, чтобы начать новый крестовый поход против сильных мира сего. Но для этого ему сперва нужен преемник — человек, который продолжит его миссию и станет новым Чумным Доктором…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3,"review":"","added":9999387,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098941a","title":"Современный Человек-Паук. Том 5. Безответственность","author":"Брайан Майкл Бендис, Марк Багли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002833582/140/a3d2/Brajan_Majkl_Bendis_Mark_Bagli__Sovremennyj_ChelovekPauk._Tom_5._Bezotvetstvenno.jpg","isbn":"","publisher":"Зодиак","pubDate":"2018","language":"Русский","series":"Современный Человек-Паук","genres":["Комиксы","манга","графические романы"],"annotation":"Сэм Буллит баллотируется в мэры Нью-Йорка с кампанией против Человека-Паука, а Джей Джона Джеймсон поддерживает его на 100 процентов. Но кто дёргает за ниточки Буллита? Не кто иной, как Кингпин, король преступности! Потом Человек-Паук встречает сексуальную и неуловимую воровку по имени Чёрная Кошка, которая коготками впилась в жизнь юного паутиноплёта и даже мурлычет на ушко Питеру Паркеру. Но затем Кошка накладывает лапы на украденную плиту, которую жаждет заполучить Кингпин, и тот нанимает смертоносную Электру, чтобы вернуть своё. А ещё сцену взрывает новый злодей – причём буквально! Но как Человеку-Пауку сражаться с загадочным Гелдоффом, если он даже костюм найти не может? И смогут ли Питер Паркер и Мэри Джейн рассказать друг другу о своих чувствах?! Приглашённые звёзды выпуска – Современные Люди Икс!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999386,"hdCover":""},{"id":"0989419","title":"Современный Человек-паук. Том 4. Веном","author":"Брайан Майкл Бендис, Марк Багли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002724064/140/923f/Brajan_Majkl_Bendis_Mark_Bagli__Sovremennyj_Chelovekpauk._Tom_4._Venom.jpg","isbn":"978-5-9909831-8-2","publisher":"Зодиак","pubDate":"2017","language":"Русский","series":"Современный Человек-паук","genres":["Комиксы","манга","графические романы"],"annotation":"Он победил Крэйвена. А также одолел Доктора Осьминога. Он даже выжил в ужасной битве с Зелёным Гоблином, искусственно нарастившем себе силу. Хотя, как выясняется, худшим врагом окажется жулик в костюме Человека-Паука. Это моментально уничтожит репутацию Паучка, сделав его врагом общества №1… И изменит его жизнь навсегда.  Далее совершенный злодей Человека-Паука получит невероятную мощь! После воссоединения со своим другом детства – Эдди Броком – Питер открыл тайну прошлого их отцов… чёрную жидкость, способную превращаться в протоплазматический костюм, исцеляя любые болезни и увеличивая силу и навыки носителя. Когда Питер попытался продолжить исследования отца, то случайно оказался поглощён тёмной жидкостью и стал неимоверно силён… но цена была ужасна.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4.5,"review":"","added":9999385,"hdCover":""},{"id":"0989418","title":"Современный Человек-паук. Том 3. Двойные проблемы","author":"Брайан Майкл Бендис, Марк Багли","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002702762/140/8acf/Brajan_Majkl_Bendis_Mark_Bagli__Sovremennyj_Chelovekpauk._Tom_3._Dvojnye_problem.jpg","isbn":"978-5-9909831-4-4","publisher":"Зодиак","pubDate":"2017","language":"Русский","series":"Современный Человек-паук","genres":[],"annotation":"Только двое знают секрет Питера. Одна – его лучшая подруга, союзница и девушка – Мэри Джейн Уотсон. Другой – безжалостный бизнесмен Норман Озборн, также известный как Зелёный Гоблин. И Озборн использует эту информацию, чтобы контролировать подростка – угрожая жизням Мэри Джейн и его любимой тёти Мэй, если Питер откажется подчиниться. Значит, Человек-Паук будет вынужден служить своему величайшему врагу, чтобы защитить тех, кого он любит? Также встречайте новое воплощение двух классических противников Паучка: Доктора Осьминога и Крэйвена-Охотника!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4.5,"review":"","added":9999384,"hdCover":""},{"id":"0989417","title":"Современный Человек-паук. Том 2. Время тренировок","author":"Брайан Майкл Бендис, Марк Багли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002143288/140/7abf/Brajan_Majkl_Bendis_Mark_Bagli__Sovremennyj_Chelovekpauk._Tom_2._Vremya_trenirov.jpg","isbn":"978-5-9909387-0-0","publisher":"Зодиак","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сперва убийство его дяди, потом нападение на школу, да еще смущающие сигналы от прекрасной Мэри Джейн Уотсон, и вот Питер осознаёт, что он уже на пороге возмужания: получает работу в нью-йоркской газете \"Дейли Бьюгл\", помогаеттёте Мэй и занимается внеклассной деятельностью... Например, свергает босса организованной преступности Уилсона фиска, также известного как Кингпин.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999383,"hdCover":""},{"id":"0989416","title":"Современный Человек-Паук Том 1. Сила и ответственность","author":"Брайан Майкл Бендис, Марк Багли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002071852/140/5de1/Brajan_Majkl_Bendis_Mark_Bagli__Sovremennyj_ChelovekPauk_Tom_1._Sila_i_otvetstve.jpg","isbn":"9785990647886","publisher":"Зодиак","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Старшая школа, взросление, первые танцы- в молодости много ловушек. Смешайте их с сильной личной трагедией и суперсилой и вы сможете представить себе мир Питера Паркера, он же Человек-Паук!  Станьте свидетелем перерождения легенды, пока Питер познаёт, что с великой силой должна прийти и великая ответственность!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999382,"hdCover":""},{"id":"0989415","title":"Injustice 2, Vol. 6","author":"Том Тейлор","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006133860/140/801b/Tom_Tejlor__Injustice_2_Vol._6.jpg","isbn":"978-1401292270","publisher":"DC Comics","pubDate":"2019","language":"","series":"Injustice","genres":[],"annotation":"Batman and Superman''s alliance was torn apart years ago by the events of Injustice. But when Bruce Wayne receives unexpected visitors, he is reminded of a happier time when Clark was his savior. A time of the World''s Finest friendship.  For more than five years, writer Tom Taylor ( Dceased, Spectacular Spider-Man) has helped craft an epic story that began with one question--What if Superman went bad?--and has since gone on to explore every corner of the DC Universe in unexpected and surprising ways. Now, the story reaches its conclusion and leads directly to the events of the hit game Injustice 2 with shocking twists!  In space, the Red Lantern Corps have allied themselves with Starro the Conqueror and it will take every member of the Green Lantern Corps--and then some--to turn back their assault on Oa. Can Hal Jordan find redemption for what he did as Superman''s ally? And more importantly...what happens when Lobo gets a Green Lantern ring?  Back on Earth, the war between Batman and Ra''s al Ghul reaches a fragile peace, but a new threat from the stars has set its sights on Earth. When Brainiac and Gorilla Grodd begin their fateful partnership, it means the end of Ra''s al Ghul''s regime and the beginning of Batman''s greatest battle ever!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999381,"hdCover":""},{"id":"0989414","title":"Injustice 2, Vol. 5","author":"Том Тейлор","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006133854/140/1e00/Tom_Tejlor__Injustice_2_Vol._5.jpg","isbn":"978-1401289164","publisher":"DC Comics","pubDate":"2019","language":"","series":"Injustice","genres":[],"annotation":"The war between Batman and Ra''s al Ghul takes unexpected turns--with consequences far beyond the Earth!  When Wayne Manor provides no safety for the Dark Knight''s closest confidants, Batman needs help from some familiar allies to reclaim his home. And as the Titans and the Red Lantern Corps get caught up in the intrigue, both teams find themselves in need of new members. With the stakes getting even higher, Metron of the New Gods warns that the end of the universe is at hand, courtesy of a more-powerful-than-ever Starro the Conqueror. Only one hero may be able to turn the tide, so now it''s up to Lobo to keep Blue Beetle Jaime Reyes alive long enough to change the fate of the entire universe!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999380,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989413","title":"Injustice 2, Vol. 4","author":"Том Тейлор","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006133851/140/9965/Tom_Tejlor__Injustice_2_Vol._4.jpg","isbn":"978-1401285333","publisher":"DC Comics","pubDate":"2018","language":"","series":"Injustice","genres":[],"annotation":"Steel (Natasha Irons) leads a task force in protecting the President-elect at the inauguration. Batman''s team is on the verge of breaking free from Ra''s al Ghul''s jungle stronghold, but the Dark Knight himself gets tangled up with Poison Ivy.  However, when a larger battle breaks out, Blue Beetle thinks he''s coming to save the day, but his inexperience leads instead to disaster... and death.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999379,"hdCover":""},{"id":"0989412","title":"Injustice 2, Vol. 3","author":"Том Тейлор","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006133845/140/5463/Tom_Tejlor__Injustice_2_Vol._3.jpg","isbn":"978-1401280291","publisher":"DC Comics","pubDate":"2018","language":"","series":"Injustice","genres":[],"annotation":"Wonder Woman takes center stage as the war between Batman and Ra''s al Ghul intensifies in Injustice 2 Vol. 3, exploring the world of the best-selling fighting game!  Nightwing a.k.a. Damian Wayne asks Black Adam''s help in freeing Wonder Woman from her Themysciran prison, but ends up discovering the existence of a new ally: Superman''s cousin, Kara Zor-El, whose power could change the fate of the planet! But Kara has yet to master her Kryptonian powers, and what starts as a rescue mission takes some unexpected turns in the heart of the Amazons'' home!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999378,"hdCover":""},{"id":"0989411","title":"Injustice 2, Vol. 2","author":"Том Тейлор","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006133839/140/2f94/Tom_Tejlor__Injustice_2_Vol._2.jpg","isbn":"978-1401278410","publisher":"DC Comics","pubDate":"2018","language":"","series":"Injustice","genres":[],"annotation":"Green Arrow and Black Canary''s walk down the aisle has devastating consequences for the Justice League, the Suicide Squad and more in Injustice 2 Volume 2, exploring the world of the best-selling fighting game Injustice 2!  What seems like a rare moment of peace and celebration is turned upside down when Damian Wayne performs a wedding-day kidnapping of the children of Arrow, Canary and Black Lightning, with the help of his grandfather, Ra''s al Ghul! Now Batman must work with a Justice League Task Force that includes Batgirl, Steel, Blue Beetle and even Plastic Man to take the fight to al Ghul''s hidden lair!  But Batman''s immortal villain has protectors of his own, including a Suicide Squad of Harley Quinn, Animal Man, El Diablo, Poison Ivy and an impostor Batman! And if they aren''t able to stop the real Batman, Ra''s has another plan that threatens the world, as a sleeper agent sets his sights on a presidential inauguration!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999377,"hdCover":""},{"id":"0989410","title":"Injustice 2, Vol. 1","author":"Том Тейлор","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006133833/140/c1cc/Tom_Tejlor__Injustice_2_Vol._1.jpg","isbn":"978-1401274412","publisher":"DC Comics","pubDate":"2017","language":"","series":"Injustice","genres":[],"annotation":"The start of an all-new saga in the alternate DC Universe of the smash-hit Warner Bros. Interactive fighting game is here in INJUSTICE 2 VOL. 1!  The war is over. But a new battle is about to begin.  After years of conflict and carnage, Batman and his rebel allies have finally triumphed over their tyrannical foe, Superman. Now the Man of Steel is behind bars, and the Dark Knight holds the future of the world in his hands.  But that future is about to slip from his grasp.  Superman still has many friends who will work tirelessly to free their leader from captivity. And a new force is about to emerge from the shadows. A winged warrior is assembling a Suicide Squad of the world’s most dangerous villains to pursue plans of his own, by any means necessary.  And this man in black is out to claim the mantle of the Batman himself.  As old foes and new enemies collide, can Bruce Wayne preserve the fragile peace for which so many heroes have sacrificed? Or is a new era of injustice about to dawn?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999376,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098940f","title":"Injustice: Ground Zero Vol. 4","author":"Chris Sebela","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002703929/140/b1e7/Chris_Sebela__Injustice_Ground_Zero_Vol._4.jpg","isbn":"","publisher":"DC Comics","pubDate":"2017","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999375,"hdCover":""},{"id":"098940e","title":"Injustice: Ground Zero Vol. 3","author":"Chris Sebela","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002696587/140/24d3/Chris_Sebela__Injustice_Ground_Zero_Vol._3.jpg","isbn":"","publisher":"DC Comics","pubDate":"2017","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999374,"hdCover":""},{"id":"098940d","title":"Injustice: Ground Zero Vol. 2","author":"Chris Sebela","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002315980/140/056e/Chris_Sebela__Injustice_Ground_Zero_Vol._2.jpg","isbn":"","publisher":"DC Comics","pubDate":"2017","language":"Английский","series":"","genres":[],"annotation":"Harley and the Joker are back together, but is Harley Quinn the typical pawn in Joker’s evil plot, or is she setting an elaborate trap for him to fall right into? Seeing as this story is told through the less-than-lucid lens of Harley, you can probably guess which side she thinks she’s on…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999373,"hdCover":""},{"id":"098940c","title":"Injustice: Ground Zero Vol. 1","author":"Chris Sebela","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002232040/140/aa92/Chris_Sebela__Injustice_Ground_Zero_Vol._1.jpg","isbn":"","publisher":"DC Comics","pubDate":"2017","language":"Английский","series":"","genres":[],"annotation":"INJUSTICE: GROUND ZERO bridges the gap between the Injustice and Injustice 2 video games with a new perspective—through Harley Quinn’s eyes! As heroes from a parallel Earth arrive to tip the balance against Superman’s regime, Harley’s determined to cause her own brand of mayhem with the Joker Clan!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999372,"hdCover":""},{"id":"098940b","title":"Фьюри: Моя война прошла давно. Том 2","author":"Гарт Эннис,Ли Лоуридж,Горан Парлов","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002706098/140/44fb/__Fyuri_Moya_vojna_proshla_davno._Tom_2.jpg","isbn":"978-985-90438-1-9","publisher":"ALDEN comics","pubDate":"2017","language":"Русский","series":"Фьюри","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4.5,"review":"","added":9999371,"hdCover":""},{"id":"098940a","title":"Фьюри: Моя война прошла давно. Том 1","author":"Гарт Эннис,Ли Лоуридж,Горан Парлов","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002000118/140/368a/__Fyuri_Moya_vojna_proshla_davno._Tom_1.jpg","isbn":"978-985-90393-5-5","publisher":"ALDEN comics","pubDate":"2016","language":"Русский","series":"Фьюри","genres":["Комиксы","манга","графические романы"],"annotation":"Гарт Эннис («Проповедник», «Каратель МАКС») и Горан Парлов («Каратель МАКС») расскажут вам историю жизни Ника Фьюри, как никто другой!  В трясине Французского Индокитая в 50-е и в Заливе Свиней в 1961 году полковник Фьюри одним из первых увидит новые войны – а вы первыми увидите, на что он готов ради своей страны. Смерть, огонь и свинец под одной обложкой – серия FURY MAX, выпуски №1-6.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999370,"hdCover":""},{"id":"0989409","title":"Тор. Плоды осады. Пожиратели миров","author":"Кирон Гиллен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003055261/140/f9c9/Kiron_Gillen__Tor._Plody_osady._Pozhirateli_mirov.jpg","isbn":"978-5-91878-334-4","publisher":"Фантастика Книжный Клуб","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Писатель Кирон Гиллен, любимец фанатов Marvel, продолжает свою историю, уже ставшую бестселлером и получившую признание критиков, — теперь в соавторстве с художниками Дагом Брейтуэйтом и Ричардом Элсоном. Незадолго до Осады Асгарда злокозненный Локи натравил на собственный народ чудовищных дис. А затем, преследуя свои цели, заключил сделку с Хелой, госпожой асгардских мёртвых, чтобы обезопасить души умерших от созданной им же угрозы. Теперь Локи мёртв, и козням его пришёл конец. Или нет? Хитроумная лазейка в его договоре с Хелой позволила Мефисто, владыке Ада и новому хозяину дис, вновь спустить на Асгард смертоносных пожирательниц плоти. Ради спасения своего народа Тор и Хела вынуждены объединиться в Аду, где Тору предстоит прорубить себе дорогу сквозь демонов, монстров, огненные озёра и мёртвые армии! Асгард лежит в руинах. Бальд Храбрый — доблестный воин, но нерешительный король. Его подданные не без оснований сомневаются, смогут ли вынести ещё хоть один удар судьбы. А на них наступает безжалостная армия зла из иного измерения: Асгард парит в небесах над Оклахомой, его исконное место среди Девяти Миров опустело — и прознавшие о том Пожиратели Миров намерены заявить на это место права. Завоеватели опустошают всё Мировое Древо — и Тор должен найти способ сплотить своё божественное семейство против страшнейшей угрозы. Включает выпуски «Тор» № 611–621, «Сиф» № 1 и материалы из «Тора» № 600.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999369,"hdCover":""},{"id":"0989408","title":"День М","author":"Брайан Майкл Бендис,Оливье Койпель","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002472583/140/a0c9/__Den_M.jpg","isbn":"978-5-9909878-1-4","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Мир, в котором исполнились все самые сокровенные мечты - утопия для одних, кошмар для других. Когда-то нервный срыв Алой Ведьмы привел к гибели нескольких героев и распаду Мстителей. Но на этом история Ванды не закончилась. Никто не знает, что делать с героиней, чьи силы постоянно выходят из под контроля. И вот происходит трагедия. Она займет всего один день, но этот день навеки изменит вселенную Marvel.  Действие сюжета \"День М\" происходит до событий Гражданской Войны. В ролях - почти все ключевые Мстители и Люди Икс, а подлинной звездой является Росомаха, для которого \"День М\" станет поворотной точкой в истории. Это законченный сюжет, который стоит читать даже если вы не очень разбираетесь во всех хитросплетениях вселенной Marvel.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999368,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989407","title":"Человек-Паук. История жизни","author":"Марк Багли,Чип Здарски","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004176018/140/b370/__ChelovekPauk._Istoriya_zhizni.jpg","isbn":"978-5-04-111669-9","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Золотая коллекция Marvel","genres":["Комиксы","манга","графические романы"],"annotation":"Человек-Паук творит историю!  В 1962 году в \"Удивительном фэнтези\" #15 пятнадцатилетний Питер Паркер был укушен радиоактивным пауком и стал удивительным Человеком-Пауком! Пятьдесят семь лет прошло в нашем мире с того момента… Так что бы стало с Питером, если бы для него прошло столько же? В честь 80-летней годовщины Marvel Чип Здарски и легенда паучьих комиксов Марк Багли объединились, чтобы сплести уникальную историю про Паучка – пересказать всю его жизнь от начала и до конца, поставив его перед значимыми событиями десятилетий, которые мы пережили! От войны во Вьетнаме, Секретных войн и Гражданской войны до миссии, которая может стать последней для 72-летнего Человека-Паука. Приготовьтесь увидеть историю жизни Питера Паркера, растянувшуюся на 57 лет поразительных сюжетов… и узнайте, что случится с ним и его родными!  Невероятная история от мастеров жанра: Чипа Здарски (\"Говард Утка\", \"Секс-преступники\", \"Джагхед\") и невероятного Марка Багли (\"Современный Человек-Паук\"). Альтернативная ветка развития событий, в которой нет места вечно юным героям, время - ещё один беспощадный враг, с которым придётся столкнуться Паучку и его товарищам. Авторы мастерскими играют чувствами читателя, заставляя его то смеяться, то плакать, то задумываться о своей жизни, судьбах мира и о том, в чьих руках они находятся.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999367,"hdCover":""},{"id":"0989406","title":"Классика Marvel. Невероятные Люди Икс","author":"Крис Клэрмонт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003640010/140/1520/Kris_Klermont__Klassika_Marvel._Neveroyatnye_Lyudi_Iks.jpg","isbn":"978-5-04-106944-5","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Люди Икс — команда одарённых подростков, движимых мечтой о мирном сожительстве всех людей и мутантов Земли. Но до тех пор им предстоит проделать много работы и пережить невероятное количество приключений! И когда команда, поклявшаяся защищать тех, кто боится их не ненавидят, нуждается в помощи... только товарищи-мутанты могут их спасти! Встречайте: Росомаха, Ночной Змей, Шторм и Колосс — Невероятные Люди Икс! Включает выпуски Uncanny X-Men #94-100 и Giant-Size X-Men #1 Криса Клэрмонта, \"крестного отца\" Людей Икс, чья работа над серией сделала мутантов самыми популярными персонажами Marvel!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":3.5,"review":"","added":9999366,"hdCover":""},{"id":"0989405","title":"Аннигиляция: Завоевание. Книга первая","author":"Кит Гиффен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003682292/140/b84b/Kit_Giffen__Annigilyatsiya_Zavoevanie._Kniga_pervaya.jpg","isbn":"978-5-91878-412-9","publisher":"Фантастика Книжный Клуб","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Этот роскошный том в твёрдой обложке — первая ласточка захватывающего продолжения «Аннигиляции». Множество старых, полюбившихся читателям космических персонажей Marvel возвращаются, чтобы завоевать признание нового поколения любителей фантастики! Хала, прародина крии, которая едва начала восстанавливаться после Войны Аннигиляции, становится главной мишенью внезапной сокрушительной атаки и стремительного вторжения. Cбросить иго захватчиков теперь может только крошечный разношёрстный отряд воителей.  Звёздный Лорд, один из самых крутых культовых героев семидесятых, возвращается — его ждут новые приключения, где в равных долях смешались головокружительное действие и искромётный юмор. Под командой Квилла на битву в тылу захватчиков отправляется «Грязная Дюжина», в рядах которой Мантис, Рогач, Грут, Енот Ракета! А тем временем новый Квазар — мятущаяся, но целеустремлённая дочь первого Капитана Марвел — ищет таинственного «спасителя». И когда откроется его личность, фанаты Marvel, перевернув последнюю страницу, будут аплодировать стоя!  Том «Аннигиляция: Завоевание. Книга первая» содержит первые главы батального полотна в научно-фантастическом жанре, о котором новостной ресурс Aint It Cool отозвался так: «Достойное продолжение, во всех смыслах равное поразительно цельному и не дающему заскучать с первой до последней страницы кроссоверу прошлого года!»  Включает выпуски: «Аннигиляция: Завоевание. Пролог», «Аннигиляция: Завоевание. Квазар № 1–4», «Аннигиляция: Завоевание. Звёздный Лорд № 1–4» и «Хроника Аннигиляции».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-07","rating":4,"review":"","added":9999365,"hdCover":""},{"id":"0989404","title":"Пэтси Уокер, она же Адская кошка! Том 1. Только от жизни кошачьей","author":"Наташа Аллегри,Кейт Лет,Бритни Л. Уильямс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002256690/140/6787/__Petsi_Uoker_ona_zhe_Adskaya_koshka_Tom_1._Tolko_ot_zhizni_koshachej.jpg","isbn":"978-5-91339-507-8","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Пэтси Уокер удалось убежать от прошлого, своих врагов и даже из Ада (буквально), но с поиском работы в Нью-Йорке не сравнится ничто! Силясь заработать на арендную плату и уворачиваясь от пуль, Пэтси едва успевает разобраться с последствиями переиздания романтических комиксов авторства её матери, основанных на реальных событиях жизни Пэтси в подростковом возрасте! И речь даже не о том, как это переиздание повлияло на её работу и личную жизнь. Что предпримет наша героиня, когда вместо двойной ей придётся вести совершенно Адскую тройную жизнь? Бургеры, чудовища и счета за квартиру, старые друзья вроде Женщины-Халк и Валькирии, а также призрак из прошлого с сомнительными намерениями! Пэтси Уокер возвращается на сцену в своей первой сольной серии комиксов аж с 60-х годов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-06","rating":2.5,"review":"","added":9999364,"hdCover":""}]');
